276â†’    private fun setCurrentCardFromNoteEditorBundle(col: Collection): Card? {
277â†’        assert(mNoteEditorBundle != null)
278â†’        currentCard = getDummyCard(mEditedNotetype, cardIndex, getBundleEditFields(mNoteEditorBundle))
279â†’        // example: a basic card with no fields provided
280â†’        if (currentCard == null) {
281â†’            return null
282â†’        }
283â†’        val newDid = mNoteEditorBundle!!.getLong("did")
284â†’        if (col.decks.isDyn(newDid)) {
285â†’            currentCard!!.oDid = currentCard!!.did
286â†’        }
287â†’        currentCard!!.did = newDid
288â†’        val currentNote = currentCard!!.note()
289â†’        val tagsList = mNoteEditorBundle!!.getStringArrayList("tags")
290â†’        setTags(currentNote, tagsList)
291â†’        return currentCard
