294â†’    /**
295â†’     * Set the set tags of currentNote to tagsList.  We make no
296â†’     * assumption on the content of tagsList, except that its strings
297â†’     * are valid tags (i.e. no spaces in it).
298â†’     */
299â†’    private fun setTags(currentNote: Note, tagsList: List<String>?) {
300â†’        val currentTags = currentNote.tags.toTypedArray()
301â†’        for (tag in currentTags) {
302â†’            currentNote.delTag(tag)
303â†’        }
304â†’        if (tagsList != null) {
305â†’            val tagsSet = currentNote.col.tags.canonify(tagsList)
306â†’            currentNote.addTags(tagsSet)
307â†’        }
308â†’    }
