310â†’    private fun getLabels(fieldValues: MutableList<String>) {
311â†’        if (mCardType != null && mCardType == getString(R.string.cloze_model_name)) {
312â†’            fieldValues[0] = getString(R.string.cloze_sample_text, "c1")
313â†’        }
314â†’        if (mCardType != null && mCardType == getString(R.string.basic_typing_model_name)) {
315â†’            fieldValues[1] = getString(R.string.basic_answer_sample_text)
316â†’        }
