319â†’    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
320â†’        val noteFields = noteEditorBundle!!.getBundle("editFields")
321â†’            ?: return mutableListOf()
322â†’        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
323â†’        // so convert this to a list of strings, with null in place of the invalid fields
324â†’        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
325â†’        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
326â†’        for (fieldOrd in noteFields.keySet()) {
327â†’            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
328â†’        }
329â†’        return mutableListOf(*ret)
330â†’    }
