343â†’     */
344â†’    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
345â†’        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
346â†’        if (notetype == null) {
347â†’            return null
348â†’        }
349â†’        if (mAllFieldsNull) {
350â†’            getLabels(fieldValues)
351â†’        }
352â†’        val n = getColUnsafe.newNote(notetype)
353â†’        var i = 0
354â†’        while (i < fieldValues.size && i < n.fields.size) {
355â†’            if (mAllFieldsNull) {
356â†’                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
357â†’                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
358â†’                ) {
359â†’                    n.setField(i, fieldValues[i])
360â†’                } else {
361â†’                    n.setField(i, "(" + fieldValues[i] + ")")
362â†’                }
363â†’            } else {
364â†’                n.setField(i, fieldValues[i])
365â†’            }
366â†’            i++
367â†’        }
368â†’        try {
369â†’            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
370â†’        } catch (e: Exception) {
371â†’            // Calling code handles null return, so we can log this for developer's interest but move on
372â†’            Timber.d(e, "getDummyCard() unable to create card")
373â†’        }
374â†’        return null
375â†’    }
