396â†’        /** if we have an unsaved note, never return empty  */
397â†’        val isEmpty: Boolean
398â†’            get() = mNote != null
399â†’
400â†’        /** Override the method that fetches the model so we can render unsaved models  */
401â†’        override fun model(): NotetypeJson {
402â†’            return mEditedNotetype ?: super.model()
403â†’        }
