405â†’        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
406â†’            if (renderOutput == null || reload) {
407â†’                val index = if (model().isCloze) {
408â†’                    0
409â†’                } else {
410â†’                    ord
411â†’                }
412â†’                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
413â†’                    note(),
414â†’                    this,
415â†’                    model(),
416â†’                    model().getJSONArray("tmpls")[index] as JSONObject,
417â†’                    fillEmpty = false
418â†’                )
419â†’                renderOutput =
420â†’                    context.render()
421â†’            }
422â†’            return renderOutput!!
423â†’        }
