427â†’private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
428â†’    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
429â†’        return this.renderOutput!!
430â†’    }
431â†’    companion object {
432â†’        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
433â†’            val card = EphemeralCard(col, null)
434â†’            card.did = 1
435â†’            card.ord = n.cardIndexToOrd(cardIndex)
436â†’
437â†’            val nt = n.notetype
438â†’            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
439â†’                0
440â†’            } else {
441â†’                cardIndex
442â†’            }
443â†’            val template = nt.tmpls[templateIdx] as JSONObject
444â†’            template.put("ord", card.ord)
445â†’
446â†’            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
447â†’                n,
448â†’                card,
449â†’                notetype = nt,
450â†’                template = template,
451â†’                fillEmpty = false
452â†’            ).render()
453â†’            card.renderOutput = output
454â†’            card.setNote(n)
455â†’            return card
456â†’        }
457â†’    }
