461â†’private fun Note.numberOfCardsEphemeral(): Int {
462â†’    // We can't use note.numberOfCards() as this uses the database value
463â†’    return when {
464â†’        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
465â†’        else -> notetype.templatesNames.size
466â†’    }
